const { app, BrowserWindow, ipcMain, dialog } = require('electron');
const path = require('path');
const { spawn } = require('child_process');

function createWindow() {
  const win = new BrowserWindow({
    width: 1200,
    height: 800,
    webPreferences: {
      preload: path.join(__dirname, 'preload.js'),
      contextIsolation: true,
      nodeIntegration: false,
    }
  });

  win.loadFile(path.join(__dirname, 'renderer', 'index.html'));
}

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});

ipcMain.handle('export-timeline', async (event, videoClips) => {
  // videoClips: [{ path: string }, ...]
  try {
    // 1. Ask user where to save
    const { canceled, filePath } = await dialog.showSaveDialog({
      title: "Export Video",
      defaultPath: "output.mp4",
      filters: [{ name: 'MP4 Video', extensions: ['mp4'] }]
    });
    if (canceled || !filePath) return { success: false, error: 'Export canceled.' };

    // 2. Prepare FFmpeg concat list file
    const concatList = videoClips.map(clip => `file '${clip.path.replace(/'/g, "'\\''")}'`).join('\n');
    const tmpDir = app.getPath('temp');
    const concatFile = path.join(tmpDir, `ironedit_concat_${Date.now()}.txt`);
    require('fs').writeFileSync(concatFile, concatList);

    // 3. Find ffmpeg.exe
    const ffmpegPath = path.join(__dirname, 'ffmpeg', 'ffmpeg.exe');
    if (!require('fs').existsSync(ffmpegPath)) {
      return { success: false, error: 'FFmpeg not found!' };
    }

    // 4. Run FFmpeg to concat
    return await new Promise((resolve) => {
      const ffmpeg = spawn(ffmpegPath, [
        '-f', 'concat',
        '-safe', '0',
        '-i', concatFile,
        '-c', 'copy',
        filePath
      ]);
      let stderr = '';
      ffmpeg.stderr.on('data', (data) => { stderr += data.toString(); });
      ffmpeg.on('close', (code) => {
        require('fs').unlinkSync(concatFile);
        if (code === 0) {
          resolve({ success: true, filePath });
        } else {
          resolve({ success: false, error: stderr });
        }
      });
    });
  } catch (e) {
    return { success: false, error: e.message };
  }
});
```

